INSERT INTO companies (id, owner_id, name, description, industry, location, website) VALUES
('c3d4e5f6-3333-4000-8000-000000000001', 'b2c3d4e5-2222-4000-8000-000000000001', 'TechVentures Bangladesh', 'Leading technology company building innovative solutions for Bangladesh and beyond. We specialize in enterprise software and AI-driven products.', 'Information Technology', 'Dhaka', 'https://techventures.example.com'),
('c3d4e5f6-3333-4000-8000-000000000002', 'b2c3d4e5-2222-4000-8000-000000000002', 'DataSoft Systems', 'Premier software development firm delivering cutting-edge data solutions and business intelligence platforms.', 'Software Development', 'Dhaka', 'https://datasoft.example.com'),
('c3d4e5f6-3333-4000-8000-000000000003', 'b2c3d4e5-2222-4000-8000-000000000003', 'GreenDelta Solutions', 'Sustainable technology solutions provider focused on green energy and environmental monitoring systems.', 'Information Technology', 'Chittagong', 'https://greendelta.example.com'),
('c3d4e5f6-3333-4000-8000-000000000004', 'b2c3d4e5-2222-4000-8000-000000000004', 'Pathao Technologies', 'Bangladesh''s leading ride-sharing and logistics technology company, connecting millions of users daily.', 'Logistics', 'Dhaka', 'https://pathao.example.com'),
