INSERT INTO jobs (id, company_id, title, description, requirements, required_skills, preferred_skills, degree_requirement, experience_min, experience_max, job_category, location, salary_min, salary_max, employment_type) VALUES
('d4e5f6a7-4444-4000-8000-000000000001', 'c3d4e5f6-3333-4000-8000-000000000001', 'Senior Full-Stack Developer', 'We are looking for a Senior Full-Stack Developer to join our core platform team. You will be responsible for building scalable web applications using modern frameworks.', 'Strong experience with React, Node.js, and PostgreSQL. Must have experience with microservices architecture.', ARRAY['React', 'Node.js', 'TypeScript', 'PostgreSQL'], ARRAY['Docker', 'AWS', 'GraphQL'], 'bachelors', 4, 8, 'software-engineering', 'Dhaka', 60000, 120000, 'full-time'),
('d4e5f6a7-4444-4000-8000-000000000002', 'c3d4e5f6-3333-4000-8000-000000000001', 'Junior Frontend Developer', 'Join our growing team as a Junior Frontend Developer. Work on exciting UI projects with mentorship from senior engineers.', 'Basic knowledge of React and CSS. Eagerness to learn and grow.', ARRAY['HTML', 'CSS', 'JavaScript', 'React'], ARRAY['TypeScript', 'Tailwind CSS'], 'bachelors', 0, 2, 'web-development', 'Dhaka', 15000, 30000, 'full-time'),
('d4e5f6a7-4444-4000-8000-000000000003', 'c3d4e5f6-3333-4000-8000-000000000002', 'Data Scientist', 'Looking for a talented Data Scientist to build predictive models and derive insights from large datasets.', 'Strong background in statistics, machine learning, and Python programming.', ARRAY['Python', 'Machine Learning', 'SQL', 'TensorFlow'], ARRAY['Deep Learning', 'NLP', 'Spark'], 'masters', 2, 5, 'data-science', 'Dhaka', 50000, 90000, 'full-time'),
('d4e5f6a7-4444-4000-8000-000000000004', 'c3d4e5f6-3333-4000-8000-000000000002', 'Database Administrator', 'Manage and optimize our database infrastructure. Ensure high availability and performance of critical data systems.', 'Experience with PostgreSQL, MySQL, and database optimization techniques.', ARRAY['PostgreSQL', 'MySQL', 'Database Optimization', 'Linux'], ARRAY['MongoDB', 'Redis', 'Cloud Databases'], 'bachelors', 3, 7, 'it-support', 'Dhaka', 45000, 80000, 'full-time'),
('d4e5f6a7-4444-4000-8000-000000000005', 'c3d4e5f6-3333-4000-8000-000000000003', 'Mobile App Developer', 'Build cross-platform mobile applications for our environmental monitoring solutions using Flutter.', 'Experience with Flutter/Dart and mobile app deployment to app stores.', ARRAY['Flutter', 'Dart', 'Firebase', 'REST APIs'], ARRAY['iOS', 'Android', 'CI/CD'], 'bachelors', 1, 4, 'mobile-development', 'Chittagong', 30000, 55000, 'full-time'),
('d4e5f6a7-4444-4000-8000-000000000006', 'c3d4e5f6-3333-4000-8000-000000000003', 'UI/UX Designer', 'Design intuitive interfaces for our web and mobile applications. Conduct user research and create prototypes.', 'Proficiency in Figma or Sketch. Portfolio demonstrating strong design skills.', ARRAY['Figma', 'User Research', 'Prototyping', 'UI Design'], ARRAY['Adobe XD', 'Illustration', 'Motion Design'], 'bachelors', 2, 6, 'ui-ux-design', 'Chittagong', 35000, 60000, 'full-time'),
('d4e5f6a7-4444-4000-8000-000000000007', 'c3d4e5f6-3333-4000-8000-000000000004', 'DevOps Engineer', 'Join our infrastructure team to build and maintain CI/CD pipelines, manage cloud resources, and ensure system reliability.', 'Strong experience with AWS, Kubernetes, and infrastructure as code.', ARRAY['AWS', 'Kubernetes', 'Docker', 'Terraform'], ARRAY['Ansible', 'Prometheus', 'Grafana'], 'bachelors', 3, 7, 'devops', 'Dhaka', 55000, 100000, 'full-time'),
('d4e5f6a7-4444-4000-8000-000000000008', 'c3d4e5f6-3333-4000-8000-000000000004', 'Digital Marketing Manager', 'Lead our digital marketing initiatives including SEO, SEM, social media campaigns, and performance marketing.', 'Proven track record in digital marketing with measurable results.', ARRAY['SEO', 'Google Ads', 'Social Media Marketing', 'Analytics'], ARRAY['Content Strategy', 'Email Marketing', 'A/B Testing'], 'bachelors', 3, 6, 'digital-marketing', 'Dhaka', 40000, 70000, 'full-time'),
('d4e5f6a7-4444-4000-8000-000000000009', 'c3d4e5f6-3333-4000-8000-000000000004', 'Cybersecurity Analyst', 'Protect our systems and user data from security threats. Perform vulnerability assessments and implement security protocols.', 'Experience in network security, threat analysis, and security compliance.', ARRAY['Network Security', 'SIEM', 'Vulnerability Assessment', 'Python'], ARRAY['Penetration Testing', 'SOC Operations', 'ISO 27001'], 'bachelors', 2, 5, 'cybersecurity', 'Dhaka', 45000, 80000, 'full-time'),
('d4e5f6a7-4444-4000-8000-000000000010', 'c3d4e5f6-3333-4000-8000-000000000005', 'Backend Engineer', 'Build robust backend services for our e-commerce platform handling millions of daily orders.', 'Strong experience with Java/Spring Boot or Node.js. Understanding of distributed systems.', ARRAY['Java', 'Spring Boot', 'Microservices', 'PostgreSQL'], ARRAY['Redis', 'Kafka', 'Elasticsearch'], 'bachelors', 2, 5, 'software-engineering', 'Dhaka', 40000, 75000, 'full-time'),
('d4e5f6a7-4444-4000-8000-000000000011', 'c3d4e5f6-3333-4000-8000-000000000005', 'Project Manager', 'Manage cross-functional projects from inception to delivery. Coordinate between engineering, product, and business teams.', 'PMP or equivalent certification preferred. Experience with Agile methodologies.', ARRAY['Agile', 'Scrum', 'JIRA', 'Stakeholder Management'], ARRAY['PMP', 'Risk Management', 'Budget Management'], 'bachelors', 5, 10, 'project-management', 'Dhaka', 60000, 110000, 'full-time'),
('d4e5f6a7-4444-4000-8000-000000000012', 'c3d4e5f6-3333-4000-8000-000000000001', 'QA Engineer Intern', 'Learn quality assurance practices while testing our web and mobile applications. Great opportunity for fresh graduates.', 'Basic understanding of software testing concepts. Attention to detail.', ARRAY['Manual Testing', 'Bug Reporting', 'Test Cases'], ARRAY['Selenium', 'JIRA', 'API Testing'], 'bachelors', 0, 1, 'software-engineering', 'Dhaka', 15000, 20000, 'internship'),
('d4e5f6a7-4444-4000-8000-000000000013', 'c3d4e5f6-3333-4000-8000-000000000003', 'Content Writer', 'Create engaging content for our blog, social media, and marketing materials about environmental technology.', 'Excellent writing skills in English and Bengali. Understanding of SEO principles.', ARRAY['Content Writing', 'SEO', 'Social Media', 'Research'], ARRAY['WordPress', 'Copywriting', 'Video Scripts'], 'bachelors', 1, 3, 'content-writing', 'Chittagong', 20000, 35000, 'full-time'),
('d4e5f6a7-4444-4000-8000-000000000014', 'c3d4e5f6-3333-4000-8000-000000000005', 'Part-time Accounting Assistant', 'Assist with day-to-day accounting tasks including invoice processing, reconciliation, and financial reporting.', 'Degree in Commerce or Accounting. Proficiency in Excel and accounting software.', ARRAY['Excel', 'Financial Analysis', 'Accounting', 'QuickBooks'], ARRAY['Tally', 'SAP', 'Tax Filing'], 'bachelors', 0, 2, 'accounting', 'Dhaka', 15000, 25000, 'part-time'),
('d4e5f6a7-4444-4000-8000-000000000015', 'c3d4e5f6-3333-4000-8000-000000000004', 'React Native Developer', 'Develop and maintain our rider and driver mobile applications built with React Native.', 'Experience building production React Native apps. Understanding of mobile performance optimization.', ARRAY['React Native', 'JavaScript', 'TypeScript', 'Mobile Development'], ARRAY['Redux', 'GraphQL', 'App Store Deployment'], 'bachelors', 2, 5, 'mobile-development', 'Dhaka', 40000, 70000, 'full-time');
